#include <bits/stdc++.h>
using namespace std;
int n,m,a[1003][1003],s[1003][1003],c,ans,x,y;
int main(){
    cin>>n>>m>>c;
    x=y=1;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
            s[i][j]=s[i-1][j]+s[i][j-1]-s[i-1][j-1]+a[i][j];
            if(i==c && j==c)ans=s[i][j];
            else if(i>=c && j>=c && ans<s[i][j]-s[i-c][j]-s[i][j-c]+s[i-c][j-c]){
            	ans=s[i][j]-s[i-c][j]-s[i][j-c]+s[i-c][j-c];
            	x=i-c+1,y=j-c+1;
			}
        }
    }
    cout<<x<<' '<<y;
    return 0;
}
